-- =====================================================================
-- 0009_seed_tema_west.sql
-- Official EC 2024 polling stations for TEMA WEST constituency
-- Source: Electoral Commission of Ghana, List of Polling Stations for the
-- 2024 General Elections (uploaded Tema_West_Polling_Stations.pdf).
-- 283 polling stations across 11 electoral areas.
-- This data is verified from the official EC list — do NOT edit names/codes
-- by hand; re-run the importer against a newer EC list when the EC revises
-- polling stations for the next electoral cycle.
-- =====================================================================

-- Columns to hold the official EC identifier + electoral-area grouping
alter table polling_stations add column if not exists station_code text unique;
alter table polling_stations add column if not exists electoral_area int;

-- 1) Region -> District -> Constituency (idempotent)
insert into regions (name) values ('Greater Accra')
on conflict (name) do nothing;

insert into districts (region_id, name)
select r.id, 'Tema West' from regions r where r.name = 'Greater Accra'
on conflict (region_id, name) do nothing;

insert into constituencies (district_id, name)
select d.id, 'Tema West'
from districts d join regions r on d.region_id = r.id
where r.name = 'Greater Accra' and d.name = 'Tema West'
on conflict (district_id, name) do nothing;

-- 2) Polling stations (283) under Tema West
with tw as (
  select c.id as cid
  from constituencies c
  join districts d on c.district_id = d.id
  join regions r on d.region_id = r.id
  where r.name = 'Greater Accra' and d.name = 'Tema West' and c.name = 'Tema West'
)
insert into polling_stations (constituency_id, name, station_code, electoral_area)
select tw.cid, v.name, v.code, v.ea
from tw,
